using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLineNumber()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooFewDigits_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooManyDigits_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345678901");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_NameOnly_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_NameOnly_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsFullGreeting()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.AreEqual("Dear Dr. Jones,", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_EmptyName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.IsFalse(result.StartsWith('-'), "Slug should not start with a dash.");
        Assert.IsFalse(result.EndsWith('-'), "Slug should not end with a dash.");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("hello    world");

        Assert.AreEqual("hello-world", result);
        Assert.IsFalse(result.Contains("--"), "Slug should not contain consecutive dashes.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(10m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_ExactValue_ReturnsExpected()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        StringAssert.EndsWith(result, "0.00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        StringAssert.Contains(result, "-");
    }
}

